mapper.select:
SELECT m.*
FROM member_info m
         JOIN member_oauth o ON m.MEMBER_SEQ = o.MEMBER_SEQ
WHERE o.PROVIDER = #{provider}
  AND o.PROVIDER_ID = #{provider_id}

