mapper.select:
SELECT COUNT(*)
  FROM member_info
 WHERE LOGIN_ID = #{login_id}

SELECT COUNT(*)
  FROM member_info
 WHERE MEMBER_EMAIL = #{member_email}

SELECT COUNT(*)
  FROM member_info
 WHERE MEMBER_NICKNM = #{member_nicknm}

SELECT COUNT(*)
  FROM member_info
 WHERE MEMBER_NICKNM = #{member_nicknm}
   AND MEMBER_SEQ != #{member_seq}
   AND MEMBER_DELETED_DTM IS NULL

