UPDATE member_info
   SET MEMBER_NICKNM = #{member_nicknm}
     , MEMBER_TEL_NO = #{member_tel_no}
     , UPD_DTM = NOW()
 WHERE MEMBER_SEQ = #{member_seq}

mapper.select:
